import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.BYehg5q7.js";const p=JSON.parse('{"title":"Focus Card","description":"","frontmatter":{},"headers":[],"relativePath":"guide/focus-card.md","filePath":"guide/focus-card.md","lastUpdated":1772692870000}'),i={name:"guide/focus-card.md"};function s(n,e,d,h,c,l){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="focus-card" tabindex="-1">Focus Card <a class="header-anchor" href="#focus-card" aria-label="Permalink to &quot;Focus Card&quot;">​</a></h1><p>The Focus Card is a single AI-generated sentence at the top of your dashboard that surfaces the most important insight from your current lab data. It gives you a quick orientation every time you open the app.</p><h2 id="when-it-appears" tabindex="-1">When It Appears <a class="header-anchor" href="#when-it-appears" aria-label="Permalink to &quot;When It Appears&quot;">​</a></h2><p>The Focus Card is only shown when two conditions are met:</p><ol><li>You have lab data loaded</li><li>You have an AI provider configured (Anthropic, OpenRouter, Venice, or Local AI)</li></ol><p>If either condition is not met, the card does not appear. See <a href="/docs/guide/ai-providers.html">AI Providers</a> to set up a provider.</p><h2 id="what-it-shows" tabindex="-1">What It Shows <a class="header-anchor" href="#what-it-shows" aria-label="Permalink to &quot;What It Shows&quot;">​</a></h2><p>The AI reads your full context — all lab entries, your nine <a href="/docs/guide/context-cards.html">Context Cards</a>, your <a href="/docs/guide/interpretive-lens.html">Interpretive Lens</a>, your sex, and your date of birth — and distills it into one sentence. This might be:</p><ul><li>The marker showing the most meaningful change since your last draw</li><li>A pattern across multiple markers worth investigating</li><li>A positive trend aligned with one of your <a href="/docs/guide/health-goals.html">Health Goals</a></li><li>A concern the AI thinks deserves attention first</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The Focus Card is deliberately brief. Its job is to point you toward something worth exploring — then you can dig deeper in the <a href="/docs/guide/ai-chat.html">AI Chat</a> or the detail view for that marker.</p></div><h2 id="caching" tabindex="-1">Caching <a class="header-anchor" href="#caching" aria-label="Permalink to &quot;Caching&quot;">​</a></h2><p>The Focus Card is cached so it does not make an API call every time you load the dashboard. It regenerates only when something meaningful changes: new lab entries, updated context cards, a different interpretive lens, or a change to your profile (sex or date of birth).</p><p>While the card is loading for the first time or after a change, you will see a shimmer animation in its place. Generation times out after 15 seconds.</p><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><p>The Focus Card request is sent to your configured AI provider. Your data is processed according to that provider&#39;s privacy policy. If you are using <a href="/docs/guide/ai-providers.html#local-ai-fully-local">Local AI</a>, the request stays entirely on your device.</p>',15)])])}const f=a(i,[["render",s]]);export{p as __pageData,f as default};
